<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import PageHeader from '@/components/PageHeader.vue'; import StatusTag from '@/components/StatusTag.vue'; import type { Batch, Certificate, IssueResult, Project, Student, Template } from '@/types'; import { deleteCertificate, evidenceCertificate, getCertificates, issueCertificates, reissueCertificate, revokeCertificate } from '@/api/certificates'; import { getProjects } from '@/api/projects'; import { getTemplates } from '@/api/templates'; import { getBatches } from '@/api/batches'; import { getStudents } from '@/api/students'; import { ElMessage, ElMessageBox } from 'element-plus'
const loading=ref(false),issueDrawer=ref(false),detail=ref(false),reissueDialog=ref(false),rows=ref<Certificate[]>([]),total=ref(0),current=ref<Certificate>(),projects=ref<Project[]>([]),templates=ref<Template[]>([]),batches=ref<Batch[]>([]),students=ref<Student[]>([]),issueResult=ref<IssueResult>();const query=reactive({current:1,size:10,keyword:'',status:''});const issueForm=reactive({project_id:0,template_id:0,batch_id:0,student_ids:[] as number[],issue_date:''});const reissueForm=reactive({reason:'',issue_date:''})
async function load(){loading.value=true;try{const p=await getCertificates(query);rows.value=p.records;total.value=p.total}catch{rows.value=[]}finally{loading.value=false}}function reset(){query.keyword='';query.status='';query.current=1;load()}async function openIssue(){issueDrawer.value=true;issueResult.value=undefined;const q={current:1,size:100,keyword:'',status:''};const [p,t,b,s]=await Promise.all([getProjects(q),getTemplates(q),getBatches(q),getStudents(q)]);projects.value=p.records;templates.value=t.records;batches.value=b.records;students.value=s.records}
async function issue(){if(!issueForm.project_id||!issueForm.template_id||!issueForm.batch_id||!issueForm.student_ids.length||!issueForm.issue_date)return ElMessage.warning('请完整选择签发信息');issueResult.value=await issueCertificates(issueForm);ElMessage.success('签发任务完成');load()}async function evidence(row:Certificate){await evidenceCertificate(row.certificate_id);ElMessage.success('存证成功');load()}
async function revoke(row:Certificate){const {value:reason}=await ElMessageBox.prompt('请输入撤销原因','撤销证书',{inputValidator:v=>Boolean(v)||'必须填写撤销原因'});await ElMessageBox.confirm(`确认撤销证书 ${row.certificate_no}？撤销后不可恢复。`,'二次确认',{type:'warning'});await revokeCertificate(row.certificate_id,reason);ElMessage.success('证书已撤销');load()}
function openReissue(row:Certificate){current.value=row;Object.assign(reissueForm,{reason:'',issue_date:''});reissueDialog.value=true}async function reissue(){if(!current.value||!reissueForm.reason||!reissueForm.issue_date)return ElMessage.warning('请填写补发原因和签发日期');await reissueCertificate(current.value.certificate_id,reissueForm);ElMessage.success('补发成功，新证书已创建');reissueDialog.value=false;load()}function show(row:Certificate){current.value=row;detail.value=true}async function remove(row:Certificate){await ElMessageBox.confirm(`确认删除草稿证书 ${row.certificate_no}？`,'删除证书',{type:'warning'});await deleteCertificate(row.certificate_id);ElMessage.success('删除成功');load()}onMounted(load)
</script>
<template><div><PageHeader title="证书管理" description="批量签发、下载、存证、撤销与补发证书"><el-button type="primary" @click="openIssue">批量签发</el-button></PageHeader><section class="panel"><div class="toolbar"><el-input v-model="query.keyword" placeholder="证书编号、学生或项目" clearable style="width:290px"/><el-select v-model="query.status" placeholder="状态" clearable style="width:150px"><el-option v-for="s in ['DRAFT','GENERATED','EVIDENCED','VALID','REVOKED','REISSUED','EXPIRED']" :key="s" :label="s" :value="s"/></el-select><el-button type="primary" @click="query.current=1;load()">查询</el-button><el-button @click="reset">重置</el-button></div><el-table v-loading="loading" :data="rows" empty-text="暂无证书数据"><el-table-column prop="certificate_no" label="证书编号" min-width="180"/><el-table-column prop="student_name" label="学生姓名" min-width="110"/><el-table-column prop="batch_id" label="批次ID" width="90"/><el-table-column prop="certificate_hash" label="证书哈希" min-width="220" show-overflow-tooltip/><el-table-column prop="receipt_id" label="回执编号" min-width="170" show-overflow-tooltip><template #default="s">{{s.row.receipt_id||'—'}}</template></el-table-column><el-table-column label="状态" width="110"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column label="存证状态"><template #default="s"><StatusTag :value="s.row.evidence_status"/></template></el-table-column><el-table-column label="操作" width="290"><template #default="s"><el-button link type="primary" @click="show(s.row)">详情</el-button><el-button link type="success" @click="evidence(s.row)">存证</el-button><el-button v-if="s.row.status!=='REVOKED'&&s.row.status!=='REISSUED'" link type="danger" @click="revoke(s.row)">撤销</el-button><el-button v-if="s.row.status==='REVOKED'" link type="warning" @click="openReissue(s.row)">补发</el-button><el-button v-if="s.row.status==='DRAFT'" link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><div class="pagination"><el-pagination v-model:current-page="query.current" v-model:page-size="query.size" :total="total" layout="total, sizes, prev, pager, next" @change="load"/></div></section><el-drawer v-model="issueDrawer" title="批量签发证书" size="600"><el-form label-position="top"><el-form-item label="实训项目" required><el-select v-model="issueForm.project_id" filterable style="width:100%"><el-option v-for="x in projects" :key="x.id" :label="x.name" :value="x.id"/></el-select></el-form-item><el-form-item label="证书模板" required><el-select v-model="issueForm.template_id" style="width:100%"><el-option v-for="x in templates" :key="x.template_id" :label="x.name" :value="x.template_id"/></el-select></el-form-item><el-form-item label="证书批次" required><el-select v-model="issueForm.batch_id" style="width:100%"><el-option v-for="x in batches" :key="x.batch_id" :label="x.batch_name" :value="x.batch_id"/></el-select></el-form-item><el-form-item label="选择学生" required><el-select v-model="issueForm.student_ids" multiple filterable collapse-tags style="width:100%"><el-option v-for="x in students" :key="x.student_id" :label="`${x.student_no} ${x.student_name}`" :value="x.student_id"/></el-select></el-form-item><el-form-item label="签发日期" required><el-date-picker v-model="issueForm.issue_date" type="date" value-format="YYYY-MM-DD" style="width:100%"/></el-form-item><el-button type="primary" style="width:100%" @click="issue">提交签发</el-button></el-form><el-result v-if="issueResult" :icon="issueResult.failed_count?'warning':'success'" :title="`成功 ${issueResult.success_count} 张，失败 ${issueResult.failed_count} 张`"><template #extra><el-table v-if="issueResult.failures.length" :data="issueResult.failures" size="small"><el-table-column prop="student_name" label="学生"/><el-table-column prop="reason" label="失败原因"/></el-table></template></el-result></el-drawer><el-drawer v-model="detail" title="证书详情" size="520"><div v-if="current" class="detail-list"><div><span>证书编号</span><b>{{current.certificate_no}}</b></div><div><span>学生</span><b>{{current.student_name}}</b></div><div><span>项目</span><b>{{current.project_name}}</b></div><div><span>原证书编号</span><b>{{current.previous_certificate_no||'—'}}</b></div><div><span>新证书编号</span><b>{{current.new_certificate_no||'—'}}</b></div></div></el-drawer><el-dialog v-model="reissueDialog" title="补发证书" width="500"><el-alert v-if="current" :title="`原证书：${current.certificate_no}`" type="info" :closable="false"/><el-form label-position="top" style="margin-top:16px"><el-form-item label="补发原因" required><el-input v-model="reissueForm.reason" type="textarea"/></el-form-item><el-form-item label="新签发日期" required><el-date-picker v-model="reissueForm.issue_date" type="date" value-format="YYYY-MM-DD"/></el-form-item></el-form><template #footer><el-button @click="reissueDialog=false">取消</el-button><el-button type="primary" @click="reissue">确认补发</el-button></template></el-dialog></div></template>